  const anonKeyPresent = readTrimmed(process.env.EXPO_PUBLIC_SUPABASE_ANON_KEY).length > 0;

  return json({
    ok: true,
    route: 'GET /api/ivx/owner-auth/diagnostic',
    deploymentMarker: DEPLOYMENT_MARKER,
