import SwiftUI

/// Owner Login Screen
///
/// Email + password authentication through the IVX backend auth proxy.
/// Includes links to recovery and repair (V7 emergency reset) flows.
struct LoginView: View {
    @Environment(AuthViewModel.self) private var authVM
    @State private var email: String = ""
    @State private var password: String = ""
    @State private var showPassword: Bool = false
    @State private var showRecovery: Bool = false
    @State private var showRepair: Bool = false
    @State private var loginError: String?
    @FocusState private var focusedField: Field?

    private enum Field: Hashable {
        case email, password
    }

    var body: some View {
        NavigationStack {
            ScrollView {
                VStack(spacing: 28) {
                    headerSection
                    formSection
                    if let loginError {
                        errorBanner(loginError)
                    }
                    signInButton
                    recoveryLinks
                    diagnosticSection
                }
                .padding(.horizontal, 24)
                .padding(.top, 20)
            }
            .background(backgroundGradient)
            .navigationTitle("Owner Login")
            .navigationBarTitleDisplayMode(.inline)
            .navigationDestination(isPresented: $showRecovery) {
                RecoveryView()
            }
            .navigationDestination(isPresented: $showRepair) {
                RepairView()
            }
            .toolbar {
                ToolbarItem(placement: .cancellationAction) {
                    Button("Cancel") { authVM.clearError() }
                        .tint(.white.opacity(0.7))
                }
            }
        }
        .task { await authVM.fetchDiagnostic() }
    }

    // MARK: - Header

    private var headerSection: some View {
        VStack(spacing: 12) {
            Image(systemName: "lock.shield.fill")
                .font(.system(size: 52))
                .foregroundStyle(.white)
                .symbolEffect(.pulse, options: .nonRepeating)

            Text("IVX Holdings")
                .font(.title2)
                .fontWeight(.bold)
                .foregroundStyle(.white)

            Text("Institutional Real Estate Investment Platform")
                .font(.subheadline)
                .foregroundStyle(.white.opacity(0.6))
                .multilineTextAlignment(.center)
        }
        .padding(.top, 16)
    }

    // MARK: - Form

    private var formSection: some View {
        VStack(spacing: 16) {
            inputField(
                title: "Email",
                systemImage: "envelope.fill",
                text: $email,
                placeholder: "owner@ivxholding.com",
                keyboardType: .emailAddress,
                isSecure: false,
                field: .email
            )

            inputField(
                title: "Password",
                systemImage: "lock.fill",
                text: $password,
                placeholder: "••••••••",
                keyboardType: .default,
                isSecure: !showPassword,
                field: .password,
                trailing: {
                    Button {
                        showPassword.toggle()
                    } label: {
                        Image(systemName: showPassword ? "eye.slash.fill" : "eye.fill")
                            .foregroundStyle(.white.opacity(0.4))
                    }
                    .buttonStyle(.plain)
                }
            )
        }
    }

    private func inputField(
        title: String,
        systemImage: String,
        text: Binding<String>,
        placeholder: String,
        keyboardType: UIKeyboardType,
        isSecure: Bool,
        field: Field,
        trailing: @escaping () -> AnyView = { AnyView(EmptyView()) }
    ) -> some View {
        VStack(alignment: .leading, spacing: 8) {
            Text(title)
                .font(.caption)
                .fontWeight(.medium)
                .foregroundStyle(.white.opacity(0.5))

            HStack(spacing: 12) {
                Image(systemName: systemImage)
                    .foregroundStyle(.white.opacity(0.3))
                    .frame(width: 20)

                if isSecure {
                    SecureField(placeholder, text: text)
                        .textContentType(.password)
                        .foregroundStyle(.white)
                        .focused($focusedField, equals: field)
                        .submitLabel(.go)
                        .onSubmit { Task { await signIn() } }
                } else {
                    TextField(placeholder, text: text)
                        .textContentType(field == .email ? .emailAddress : .none)
                        .keyboardType(keyboardType)
                        .textInputAutocapitalization(.never)
                        .autocorrectionDisabled()
                        .foregroundStyle(.white)
                        .focused($focusedField, equals: field)
                        .submitLabel(.next)
                        .onSubmit { focusedField = .password }
                }

                trailing()
            }
            .padding(.horizontal, 16)
            .padding(.vertical, 14)
            .background(Color.white.opacity(0.06))
            .clipShape(.rect(cornerRadius: 14))
            .overlay {
                RoundedRectangle(cornerRadius: 14)
                    .stroke(focusedField == field ? Color.white.opacity(0.3) : Color.clear, lineWidth: 1)
            }
        }
    }

    // MARK: - Sign In Button

    private var signInButton: some View {
        Button {
            Task { await signIn() }
        } label: {
            HStack(spacing: 8) {
                if authVM.isLoading {
                    ProgressView()
                        .tint(.indigo)
                } else {
                    Image(systemName: "arrow.right.circle.fill")
                }
                Text("Sign In")
                    .font(.headline)
                    .fontWeight(.semibold)
            }
            .frame(maxWidth: .infinity)
            .padding(.vertical, 16)
            .background(Color.white)
            .foregroundStyle(.indigo)
            .clipShape(.rect(cornerRadius: 14))
        }
        .disabled(authVM.isLoading || email.isEmpty || password.isEmpty)
        .opacity(email.isEmpty || password.isEmpty ? 0.6 : 1)
    }

    // MARK: - Recovery Links

    private var recoveryLinks: some View {
        VStack(spacing: 12) {
            Button {
                showRecovery = true
            } label: {
                Text("Forgot password?")
                    .font(.subheadline)
                    .foregroundStyle(.white.opacity(0.6))
            }

            Button {
                showRepair = true
            } label: {
                HStack(spacing: 6) {
                    Image(systemName: "wrench.adjustable.fill")
                    Text("Emergency Owner Recovery")
                }
                .font(.subheadline)
                .fontWeight(.medium)
                .foregroundStyle(.orange)
            }
        }
        .padding(.top, 8)
    }

    // MARK: - Diagnostic

    private var diagnosticSection: some View {
        VStack(alignment: .leading, spacing: 6) {
            Text("Backend Status")
                .font(.caption2)
                .fontWeight(.semibold)
                .foregroundStyle(.white.opacity(0.4))

            if let diag = authVM.diagnostic, diag.ok == true {
                HStack(spacing: 6) {
                    Circle()
                        .fill(.green)
